query:
-- Jogos sem nomes de times (problema de integridade)
SELECT COUNT(*) AS jogos_sem_nome_teamA FROM games WHERE teamAName IS NULL OR teamAName = '';

-- Jogos com FK de time mas sem nome
SELECT COUNT(*) AS jogos_com_teamId_sem_nome FROM games WHERE (teamAId IS NOT NULL AND (teamAName IS NULL OR teamAName = ''));

-- Fases do campeonato Gaúcho
SELECT key, label, enabled, isKnockout, `order` FROM tournament_phases WHERE tournamentId = 60001 ORDER BY `order`;

-- Distribuição de jogos por fase
SELECT phase, status, COUNT(*) AS total FROM games WHERE tournamentId = 60001 GROUP BY phase, status ORDER BY phase;

